                <div className={Classes.carousel}>
                    {/* AnimatePresence to handle enter/exit animations */}
                    <AnimatePresence mode="wait">
                        {currentItems.map((review, idx) => {
                            // Retrieve delay from our delayMap
                            const delay = delayMap[idx] || 0.1;

                            return (
                                <motion.div
                                    // Combine currentSlide + idx for a unique key
                                    key={`${currentSlide}-${idx}`}
                                    initial={{ y: -10, opacity: 0 }}
                                    animate={{ y: 0, opacity: 1 }}
                                    exit={{ y: 10, opacity: 0 }}
                                    transition={{
                                        delay,
                                        duration: 0.3,
                                    }}
                                    style={{ display: "inline-block" }}
                                >
                                    <SpotlightCard
                                        className="custom-spotlight-card"
                                        spotlightColor="rgb(225, 187, 251, 0.2)"
                                    >
                                        <div className={Classes.card}>
                                            <div className={Classes.profile}>
                                                <img
                                                    src={review.avatar}
                                                    alt={review.name}
                                                    className={Classes.avatar}
                                                    draggable={false}
                                                />
                                                <div>
                                                    <h4>{review.name}</h4>
                                                    <span>{review.company}</span>
                                                </div>
                                            </div>

                                            <div className={Classes.quoteMark}>&#10077;</div>

                                            <p className={Classes.reviewText}>{review.review} </p>
                                            <div className={Classes.cardBottom}>
                                                {/* <img src={review.bg} alt="card background" /> */}
                                            </div>
                                        </div>
                                    </SpotlightCard>
                                </motion.div>
                            );
                        })}
                    </AnimatePresence>
                </div>

                {/* Navigation arrows */}
                <div className={Classes.btnWrapper}>
                    {/* Prev Button */}
                    <button
                        onClick={goToPrev}
                        disabled={isPrevDisabled}
                        style={{
                            opacity: isPrevDisabled ? 0.5 : 1,
                        }}
                    >
                        <svg
                            style={{ transform: "rotate(180deg)" }}
                            width="18"
                            height="18"
                            viewBox="0 0 24 24"
                            fill="none"
                        >
                            <path
                                d="M5 12H19"
                                stroke="#8F9BB7"
                                strokeWidth="2"
                                strokeLinecap="round"
                                strokeLinejoin="round"
                            />
                            <path
                                d="M12 5L19 12L12 19"
                                stroke="#8F9BB7"
                                strokeWidth="2"
                                strokeLinecap="round"
                                strokeLinejoin="round"
                            />
                        </svg>
                    </button>

                    {/* Next Button */}
                    <button
                        onClick={goToNext}
                        disabled={isNextDisabled}
                        style={{
                            opacity: isNextDisabled ? 0.5 : 1,
                        }}
                    >
                        <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
