import { lazy, Suspense } from 'react';
import { Routes, Route } from 'react-router-dom';
import './App.css';

import Navbar from './components/Navbar/Navbar';
import Footer from './components/Footer/Footer';
import BottomToTop from './Animations/BottomToTop';
import { ScrollToTop } from './Hooks/usePreventScrolling';
import { HelmetProvider } from 'react-helmet-async';
import { Analytics } from "@vercel/analytics/react";
import { SpeedInsights } from "@vercel/speed-insights/react";

const Home = lazy(() => import('./pages/Home/Home'));

function App() {
    return (
        <HelmetProvider>
            <div className="app-shell">
                <ScrollToTop />
                <BottomToTop fromY={40} delay={0} duration={0.35}>
                    <Navbar />
                </BottomToTop>
                <main className="app-main">
                    <Suspense fallback={<div style={{ minHeight: '100vh', background: '#010915' }} />}>
                        <Routes>
                            <Route path="/" element={<Home />} />
                            <Route path="*" element={<Home />} />
                        </Routes>
                    </Suspense>
                </main>
                <Footer />
            </div>
            <Analytics />
            <SpeedInsights />
        </HelmetProvider>
    );
}

export default App;

import React, { useEffect } from 'react';
import Classes from './Home.module.css';
import Hero from './Sections/Hero/Hero';
import About from './Sections/About/About';
import Reviews from './Sections/Reviews/Reviews';
import Services from './Sections/Services/Services';
import FAQ from './Sections/FAQ/FAQ';
import { Helmet } from 'react-helmet-async';
import { useLocation, useNavigate } from 'react-router-dom';

export default function Home() {
    const navigateTo = useNavigate();
    const location = useLocation();

    const scrollToElement = (elementId, offset = 0) => {
        const targetElement = document.getElementById(elementId);
        if (targetElement) {
            const targetPosition = targetElement.offsetTop + offset;
            window.scroll({ top: targetPosition, behavior: 'smooth' });
        }
    };

    useEffect(() => {
        const scrollInfo = location?.state?.scrollTo;
        if (!scrollInfo) return;
        const { id, offset = 0 } = scrollInfo;
        requestAnimationFrame(() => {
            setTimeout(() => {
                scrollToElement(id, offset);
                navigateTo(location.pathname, { replace: true, state: {} });
            }, 0);
        });
    }, [location.state, location.pathname, navigateTo]);

    return (
        <>
            <Helmet>
                <title>Keerthan V | Full Stack Developer</title>
                <meta name="description" content="Keerthan V — Full Stack Developer with 1+ year experience in React.js, Next.js, Spring Boot, and PHP. Building scalable, responsive, production-ready web applications." />
                <meta name="keywords" content="Keerthan V, Full Stack Developer, React.js, Spring Boot, Next.js, PHP, Java, MySQL, AWS, Portfolio" />
                <meta name="robots" content="index, follow" />
            </Helmet>
            <div className={Classes.pageWrapper}>
                <Hero />
                <About />
                <Services />
                <Reviews />
                <FAQ />
            </div>
        </>
    );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useLocation, useNavigate } from 'react-router-dom';
import Classes from './Navbar.module.css';
import Logo from '../Logo/Logo';
import useScreenWidth from '../../Hooks/useScreenWidth';
import { scrollToElement } from '../../utils/scrollToElement';

export default function Navbar() {
    const [scrolled, setScrolled] = useState(false || window.innerWidth < 480);
    const [windowWidth, setWindowWidth] = useState(window.innerWidth);

    useEffect(() => {
        const handleScroll = () => setScrolled(window.scrollY > 50);
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    useEffect(() => {
        const handleResize = () => setWindowWidth(window.innerWidth);
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const navigateTo = useNavigate();
    const location = useLocation();
    const [activePage] = useState(location.pathname);

    const getMargin = () => {
        if (windowWidth < 700) return scrolled ? '10px 5%' : '10px 5%';
        else if (windowWidth < 1000) return scrolled ? '10px 12%' : '10px 5%';
        else if (windowWidth < 1200) return scrolled ? '10px 20%' : '10px 5%';
        else return scrolled ? '10px 25%' : '10px 7%';
    };

    const isMobile = useScreenWidth() < 480;

    const handleScrollOrNavigate = (id, offset = 0) => {
        if (location.pathname !== '/') {
            navigateTo('/', { state: { scrollTo: { id, offset } } });
        } else {
            scrollToElement(id, offset);
        }
    };

    return (
        <motion.div
            className={Classes.navbar}
            initial={{ opacity: 0 }}
            animate={{
                opacity: 1,
                margin: getMargin(),
                padding: isMobile || scrolled ? '0 30px' : '0',
                backdropFilter: isMobile || scrolled ? 'blur(24px)' : 'none',
                backgroundColor: isMobile || scrolled ? '#00000080' : 'rgba(0, 0, 0, 0)',
                borderRadius: isMobile || scrolled ? '40px' : '0',
                boxShadow: isMobile || scrolled
                    ? 'rgba(255, 255, 255, 0.2) 0px 1px 0px 0px inset, rgba(0, 0, 0, 0.16) 0px 2px 8px 0px'
                    : 'none',
            }}
            transition={{ duration: 0.3, ease: 'easeInOut' }}
        >
            <div className={Classes.gridLeft}>
                <a href="/">
                    <motion.div
                        animate={{ height: isMobile || scrolled ? '2rem' : '2.2rem' }}
                        transition={{ duration: 0.3 }}
                    >
                        <Logo />
                    </motion.div>
                </a>
            </div>
            <ul>
                <li className={activePage === '/' ? Classes.navActive : ''}>
                    <a href="/"><h5>Home</h5></a>
                </li>
                <li onClick={() => handleScrollOrNavigate('about-section', -120)} style={{ display: windowWidth < 600 ? 'none' : '' }}>
                    <h5>About</h5>
                </li>
                <li onClick={() => handleScrollOrNavigate('services-section', -30)} style={{ display: windowWidth < 400 ? 'none' : '' }}>
                    <h5>Skills</h5>
                </li>
                <li onClick={() => handleScrollOrNavigate('reviews-section', -50)} style={{ display: windowWidth < 600 ? 'none' : '' }}>
                    <h5>Projects</h5>
                </li>
                <li onClick={() => handleScrollOrNavigate('faq-section', 0)}>
                    <h5>Contact</h5>
                </li>
            </ul>
            <div className={Classes.gridRight}>
                <a href="mailto:keerthudarshu06@gmail.com">
                    <button className={Classes.quoteBtn}>
                        <h5>{isMobile ? 'Hire' : 'Hire Me'}</h5>
                    </button>
                </a>
            </div>
        </motion.div>
    );
}

