import React from "react";
import Classes from "./ProjectsLoop.module.css";

const projects = [
    { id: 1, src: "/projects/1.webp", href: "https://manecoffeee.com/", alt: "Mane Coffee" },
    { id: 2, src: "/projects/2.webp", href: "https://emirate.page.gd/", alt: "Emirates Gold" },
    { id: 3, src: "/projects/3.webp", href: "https://karate-academy-two.vercel.app/", alt: "Huura Academy" },
    { id: 4, src: "/projects/4.webp", href: "#reviews-section", alt: "Sanatana Parampara" },
    { id: 5, src: "/projects/5.webp", href: "#reviews-section", alt: "PetAndCo" },
    { id: 6, src: "/projects/6.webp", href: "https://manecoffeee.com/", alt: "Full Stack Project" },
    { id: 7, src: "/projects/7.webp", href: "#reviews-section", alt: "Web Project" },
    { id: 8, src: "/projects/8.webp", href: "#reviews-section", alt: "App Project" },
];

const slides = [...projects, ...projects, ...projects];

export default function ProjectsLoop() {
    return (
        <div className={Classes.wrapper}>
            <div className={Classes.slider}>
                <div className={Classes.track}>
                    {slides.map((project, index) => (
                        <a
                            key={`${project.id}-${index}`}
                            href={project.href}
                            target={project.href.startsWith('http') ? "_blank" : undefined}
                            rel={project.href.startsWith('http') ? "noreferrer" : undefined}
                            className={Classes.slideLink}
                        >
                            <div className={Classes.imageWrapper}>
                                <img
                                    src={project.src}
                                    alt={project.alt}
                                    className={Classes.image}
                                    loading="lazy"
                                    draggable={false}
                                />
                            </div>
                        </a>
                    ))}
                </div>
            </div>
        </div>
    );
}

.wrapper {
    position: relative;
    width: 100%;
    margin-top: 3rem;
    --logoloop-fadeColorAuto: #010915;
    overflow: hidden;
}

.wrapper::after {
    content: "";
    position: absolute;
    left: 0;
    right: 0;
    bottom: 0;
    height: 100%;
    pointer-events: none;
    z-index: 2;
    background: linear-gradient(to top, rgba(1,9,21,1) 0%, rgba(1,9,21,0.75) 25%, rgba(1,9,21,0.5) 50%, rgba(1,9,21,0.25) 75%, rgba(1,9,21,0) 100%);
}

.slider {
    position: relative;
    width: 100%;
    overflow: hidden;
}

.slider::before,
.slider::after {
    content: "";
    position: absolute;
    top: 0;
    bottom: 0;
    width: clamp(24px, 15%, 20%);
    pointer-events: none;
    z-index: 3;
}

.slider::before {
    left: 0;
    background: linear-gradient(to right, var(--logoloop-fadeColorAuto) 0%, rgba(0,0,0,0) 100%);
}

.slider::after {
    right: 0;
    background: linear-gradient(to left, var(--logoloop-fadeColorAuto) 0%, rgba(0,0,0,0) 100%);
}

.track {
    display: flex;
    align-items: center;
    width: max-content;
    animation: marquee 35s linear infinite;
    will-change: transform;
}

.track:hover {
    animation-play-state: paused;
}

@keyframes marquee {
    0% { transform: translateX(0); }
    100% { transform: translateX(calc(-100% / 3)); }
}

.slideLink {
    display: block;
    padding: 0.5rem;
    text-decoration: none;
    flex-shrink: 0;
    width: clamp(140px, 18vw, 220px);
}

.imageWrapper {
    position: relative;
    width: 100%;
    border-radius: 10px;
    overflow: hidden;
}

.image {
    width: 100%;
    height: auto;
    display: block;
    border-radius: inherit;
    transform: scale(1);
    transition: transform 200ms ease-out, filter 200ms ease-out, opacity 200ms ease-out;
    opacity: 0.8;
}

.slideLink:hover .image {
    opacity: 1;
    transform: scale(1.05);
    filter: brightness(1.03);
}

@media (max-width: 799px) {
    .wrapper { --logoloop-fadeColorAuto: #0c0f25; }
    .slideLink { width: clamp(110px, 22vw, 170px); }
}

@media (max-width: 480px) {
    .wrapper { --logoloop-fadeColorAuto: #11132c; }
    .imageWrapper { border-radius: 7px; }
    .slideLink { padding: 4px; width: clamp(90px, 28vw, 140px); }
    .slideLink:hover .image { transform: scale(1); }
}
